        "training_title" to "TRAINING",
        "quick_farming_tips" to "Quick Farming Tips",
        "video_tutorials" to "Video Tutorials",
        "tip_1_title" to "Feeding Strategy",
        "tip_1_content" to "High-quality feed is essential. Ensure pigs have constant access to fresh water and balanced nutrition tailored to their growth stage.",
        "tip_2_title" to "Disease Prevention",
        "tip_2_content" to "Biosecurity is key. Limit visitors, provide footbaths, and maintain a strict vaccination schedule with your veterinarian.",
        "tip_3_title" to "Piglet Care",
        "tip_3_content" to "Keep newborn piglets warm and ensure they receive colostrum within the first few hours of birth to build immunity.",
        "tip_4_title" to "Waste Management",
        "tip_4_content" to "Proper manure handling prevents odor and disease. Consider composting or using waste as fertilizer for crops.",
        "tip_5_title" to "Record Keeping",
        "tip_5_content" to "Track growth, health, and financials meticulously to identify trends and improve farm profitability.",
        "video_1_title" to "Modern Pig Farming Basics",
        "video_2_title" to "Advanced Feeding Guide",
        "video_3_title" to "Pig Housing Design",
        "video_4_title" to "Health and Vaccination",
