        "dis_ear_necrosis_prev" to "Giảm mật độ nuôi và điều trị nhiễm trùng thứ phát.",
        "dis_sunburn" to "Cháy nắng",
        "dis_sunburn_desc" to "Ảnh hưởng đến heo trắng nuôi ngoài trời.",
        "dis_sunburn_prev" to "Cung cấp bóng mát.",
        "dis_tail_biting" to "Cắn đuôi",
        "dis_tail_biting_desc" to "Vấn đề hành vi do stress hoặc buồn chán.",
        "dis_tail_biting_prev" to "Giảm stress và làm phong phú môi trường.",
        "dis_navel_ill" to "Viêm rốn (Navel Ill)",
        "dis_navel_ill_desc" to "Nhiễm trùng dây rốn khi sinh.",
        "dis_navel_ill_prev" to "Sát trùng rốn bằng cồn i-ốt khi sinh và giữ vệ sinh.",
        "dis_iron_toxicity" to "Ngộ độc sắt",
        "dis_iron_toxicity_desc" to "Có thể xảy ra nếu tiêm sắt cho heo con thiếu Vitamin E.",
        "dis_iron_toxicity_prev" to "Đảm bảo khẩu phần ăn của nái cân bằng.",
        "training_title" to "ĐÀO TẠO",
        "quick_farming_tips" to "Mẹo Chăn Nuôi Nhanh",
        "video_tutorials" to "Hướng Dẫn Video",
        "tip_1_title" to "Chiến Lược Cho Ăn",
        "tip_1_content" to "Thức ăn chất lượng cao là thiết yếu. Đảm bảo lợn luôn được tiếp cận với nước sạch và dinh dưỡng cân bằng phù hợp với từng giai đoạn phát triển.",
        "tip_2_title" to "Phòng Chống Dịch Bệnh",
        "tip_2_content" to "An toàn sinh học là chìa khóa. Hạn chế khách tham quan, cung cấp bồn ngâm chân và duy trì lịch tiêm phòng nghiêm ngặt với bác sĩ thú y của bạn.",
        "tip_3_title" to "Chăm Sóc Lợn Con",
        "tip_3_content" to "Giữ ấm cho lợn con mới sinh và đảm bảo chúng nhận được sữa đầu trong vòng vài giờ đầu sau khi sinh để xây dựng khả năng miễn dịch.",
        "tip_4_title" to "Quản Lý Chất Thải",
        "tip_4_content" to "Xử lý phân đúng cách giúp ngăn ngừa mùi hôi và dịch bệnh. Cân nhắc ủ phân hoặc sử dụng chất thải làm phân bón cho cây trồng.",
        "tip_5_title" to "Ghi Chép Hồ Sơ",
        "tip_5_content" to "Theo dõi tỉ mỉ sự tăng trưởng, sức khỏe và tài chính để xác định xu hướng và cải thiện lợi nhuận của trang trại.",
        "video_1_title" to "Cơ Bản Về Chăn Nuôi Lợn Hiện Đại",
        "video_2_title" to "Hướng Dẫn Cho Ăn Nâng Cao",
        "video_3_title" to "Thiết Kế Chuồng Trại",
        "video_4_title" to "Sức Khỏe và Tiêm Phòng",
        "last_updated" to "Cập nhật lần cuối: %s",
        "edit_profile_title" to "Chỉnh sửa hồ sơ",
        "save_changes" to "Lưu thay đổi",
        "login_credentials" to "Thông tin đăng nhập",
        "new_password_hint" to "Mật khẩu mới (để trống nếu không đổi)",
        "confirm_new_password" to "Xác nhận mật khẩu mới",
        "tos_acceptance_title" to "1. Chấp nhận các điều khoản",
        "tos_acceptance_content" to "Bằng cách truy cập và sử dụng ứng dụng SmartSwine, bạn đồng ý tuân thủ các Điều khoản dịch vụ này. Nếu bạn không đồng ý, vui lòng không sử dụng dịch vụ.",
        "tos_description_title" to "2. Mô tả dịch vụ",
        "tos_description_content" to "\"SmartSwine\" cung cấp các công cụ quản lý trang trại bao gồm:\n• Theo dõi đàn và dữ liệu sức khỏe.\n• Ghi chép hồ sơ tài chính.\n• Quản lý nhân sự.\n• Gợi ý chẩn đoán hỗ trợ bởi AI.\n• Thông tin tiếp cận thị trường.",
        "tos_data_privacy_title" to "3. Quyền riêng tư dữ liệu và Sao lưu đám mây",
        "tos_data_privacy_content" to "Bạn giữ quyền sở hữu dữ liệu bạn nhập. Dữ liệu của bạn được lưu trữ an toàn bằng Google Firebase. Mặc dù chúng tôi cố gắng bảo vệ nó, chúng tôi không thể đảm bảo an ninh tuyệt đối. Bằng cách bật Sao lưu đám mây, bạn đồng ý với việc lưu trữ và đồng bộ dữ liệu. Chúng tôi không bán dữ liệu của bạn cho bên thứ ba.",
        "tos_no_medical_title" to "4. Không có lời khuyên y tế hoặc thú y",
        "tos_no_medical_content" to "Các tính năng AI và máy tính chỉ dành cho mục đích giáo dục. Kết quả không thay thế cho lời khuyên thú y chuyên nghiệp. Người dùng đồng ý tham vấn bác sĩ thú y trước khi đưa ra bất kỳ quyết định y tế nào.",
        "tos_user_resp_title" to "5. Trách nhiệm của người dùng",
        "tos_user_resp_content" to "Người dùng có trách nhiệm bảo mật thông tin đăng nhập của mình. Bạn chịu trách nhiệm cho tất cả các hoạt động xảy ra dưới tài khoản của mình.",
        "tos_prohibited_title" to "6. Hành vi bị cấm",
        "tos_prohibited_content" to "Người dùng đồng ý không: sử dụng ứng dụng cho mục đích bất hợp pháp, cố gắng thiết kế ngược ứng dụng hoặc nhập dữ liệu gian lận.",
        "tos_availability_title" to "7. Tính sẵn có của dịch vụ",
        "tos_availability_content" to "Chúng tôi nỗ lực đạt 99% thời gian hoạt động nhưng không đảm bảo quyền truy cập không bị gián đoạn. Các bản sao lưu được cung cấp để thuận tiện; người dùng nên tự lưu giữ hồ sơ riêng.",
        "tos_liability_title" to "8. Giới hạn trách nhiệm",
        "tos_liability_content" to "Ứng dụng được cung cấp \"nguyên trạng\". Trong phạm vi pháp luật cho phép, các nhà phát triển sẽ không chịu trách nhiệm cho bất kỳ thiệt hại nào phát sinh từ việc sử dụng dịch vụ.",
        "tos_financial_data_title" to "9. Dữ liệu tài chính",
        "tos_financial_data_content" to "Mô-đun tài chính là một công cụ theo dõi và không cấu thành lời khuyên kế toán chuyên nghiệp. Người dùng nên xuất dữ liệu để các chuyên gia soát xét.",
        "tos_changes_title" to "10. Thay đổi các điều khoản",
        "tos_changes_content" to "Chúng tôi có quyền sửa đổi các điều khoản này bất cứ lúc nào. Việc tiếp tục sử dụng ứng dụng đồng nghĩa với việc chấp nhận các điều khoản mới.",
        "tos_contact_title" to "11. Thông tin liên hệ",
        "tos_contact_content" to "Để được hỗ trợ hoặc có thắc mắc pháp lý, vui lòng liên hệ với nhà phát triển thông qua cài đặt hồ sơ của ứng dụng.",
        "contact_support" to "Liên hệ hỗ trợ: %s",
        "quote_1" to "Nông nghiệp là nghề nghiệp lành mạnh nhất, hữu ích nhất và cao quý nhất của con người. - George Washington",
        "quote_2" to "Người nông dân là người duy nhất trong nền kinh tế của chúng ta mua mọi thứ với giá bán lẻ, bán mọi thứ với giá bán buôn và trả tiền cước vận chuyển cả hai chiều. - John F. Kennedy",
        "quote_3" to "Nông nghiệp là một nghề nghiệp của hy vọng. - Brian Brett",
        "quote_4" to "Mục tiêu cuối cùng của canh tác không phải là trồng cây, mà là sự nuôi dưỡng và hoàn thiện con người. - Masanobu Fukuoka",
        "quote_5" to "Làm việc chăm chỉ làm nổi bật tính cách của con người: một số người xắn tay áo, một số người hếch mũi và một số người hoàn toàn không xuất hiện. - Sam Ewing",
        "quote_6" to "Sự kiên trì đối với tính cách của con người giống như carbon đối với thép. - Napoleon Hill",
        "quote_7" to "Thành công không phải là cuối cùng, thất bại không phải là tử vong: lòng can đảm để tiếp tục mới là điều quan trọng. - Winston Churchill",
        "quote_8" to "Nơi duy nhất mà thành công đứng trước công việc là trong từ điển. - Vidal Sassoon",
        "quote_9" to "Đừng đánh giá mỗi ngày qua vụ thu hoạch bạn gặt hái được mà hãy đánh giá qua những hạt giống bạn gieo trồng. - Robert Louis Stevenson",
        "quote_10" to "Cách tốt nhất để dự đoán tương lai của bạn là tạo ra nó. - Abraham Lincoln",
        "quote_11" to "Sự chăm chỉ đánh bại tài năng khi tài năng không làm việc chăm chỉ. - Tim Notke",
        "quote_12" to "Nông nghiệp trông có vẻ rất dễ dàng khi cái cày của bạn là một cây bút chì và bạn cách cánh đồng ngô một ngàn dặm. - Dwight D. Eisenhower",
        "quote_13" to "Mắt của chủ làm béo con heo. - Ngạn ngữ",
        "quote_14" to "Những điều lớn lao được thực hiện bởi một loạt những điều nhỏ bé được tập hợp lại với nhau. - Vincent Van Gogh",
        "quote_15" to "Nền tảng của mọi quốc gia là giáo dục thanh thiếu niên. - Diogenes",
        "quote_16" to "Cuộc sống trong trang trại là một ngôi trường của lòng kiên nhẫn. Bạn không thể thúc giục cây trồng hay tạo ra một con bò trong hai ngày. - Henri Alain",
        "quote_17" to "Nông nghiệp không chỉ là một công việc, đó là một lối sống. - Khuyết danh",
        "quote_18" to "Mục tiêu không phải là tốt hơn người khác, mà là tốt hơn chính bản thân mình trước đây. - Đạt Lai Lạt Ma",
        "quote_19" to "Sự bền vững là về tương lai của con cái và cháu chắt chúng ta. - Khuyết danh",
        "quote_20" to "Nhiệm vụ đầu tiên của một người nông dân là để lại đất đai tốt hơn so với khi anh ta tìm thấy nó. - Khuyết danh",
        "quote_21" to "Làm việc chăm chỉ trong im lặng, hãy để thành công của bạn là tiếng ồn của bạn. - Frank Ocean",
        "quote_22" to "Sự kiên trì có thể biến thất bại thành thành tựu phi thường. - Matt Biondi",
        "quote_23" to "Công việc của một người nông dân không bao giờ kết thúc, nhưng phần thưởng là vĩnh cửu. - Khuyết danh",
        "quote_24" to "Mỗi ngày là một cơ hội mới để phát triển. - Khuyết danh",
        "quote_25" to "Sự tăng trưởng không bao giờ là do ngẫu nhiên; nó là kết quả của các lực lượng làm việc cùng nhau. - James Cash Penney",
        "quote_26" to "Cuộc sống giản đơn là phần thưởng của riêng nó. - Khuyết danh",
        "quote_27" to "Nông dân là xương sống của thế giới. - Khuyết danh",
        "quote_28" to "Một cánh đồng chỉ tốt bằng người chăm sóc nó. - Khuyết danh",
        "quote_29" to "Đối với một người nông dân, mỗi hạt giống là một lời hứa. - Khuyết danh",
        "quote_30" to "Đức tin là con chim cảm nhận được ánh sáng khi bình minh vẫn còn tối. - Rabindranath Tagore",
        "quote_31" to "Thành công thường đến với những người quá bận rộn để tìm kiếm nó. - Henry David Thoreau",
        "quote_32" to "Không có đường tắt đến bất cứ nơi nào xứng đáng để đi. - Beverly Sills",
        "quote_33" to "Hãy tin rằng bạn có thể và bạn đã đi được nửa đường. - Theodore Roosevelt",
        "quote_34" to "Trái tim bạn giống như một khu vườn. Bạn có thể trồng hoa hoặc bạn có thể trồng cỏ dại. - Khuyết danh",
        "quote_35" to "Sự khám phá ra nông nghiệp là bước tiến lớn đầu tiên hướng tới một cuộc sống văn minh. - Arthur Keith",
        "quote_36" to "Những người canh tác đất đai là những công dân có giá trị nhất. - Thomas Jefferson",
        "quote_37" to "Người nông dân phải là một người lạc quan, nếu không anh ta sẽ không còn là một người nông dân nữa. - Will Rogers",
        "quote_38" to "Chỉ có người nông dân trung thành gieo hạt vào mùa xuân mới gặt hái được vụ thu hoạch vào mùa thu. - B.C. Forbes",
        "quote_39" to "Không có chủng tộc nào có thể thịnh vượng cho đến khi họ học được rằng có nhiều phẩm giá trong việc cày ruộng cũng như trong việc viết một bài thơ. - Booker T. Washington",
        "quote_40" to "Nếu bạn thọc lét đất đai bằng một cái cuốc, cô ấy sẽ cười bằng một vụ thu hoạch. - Douglas Jerrold",
        "quote_41" to "Nông nghiệp không chỉ mang lại sự giàu có cho một quốc gia, mà là sự giàu có duy nhất mà quốc gia đó có thể gọi là của riêng mình. - Samuel Johnson",
        "quote_42" to "Nghệ thuật nông nghiệp là nghệ thuật làm đối tác với Chúa. - Khuyết danh",
        "quote_43" to "Trở thành một nông dân có nghĩa là bạn có rất nhiều sự kiên nhẫn. - Khuyết danh",
        "quote_44" to "Mọi thứ làm chúng ta chậm lại và buộc chúng ta phải kiên nhẫn, mọi thứ đưa chúng ta trở lại chu kỳ chậm chạp của thiên nhiên, đều là một sự trợ giúp. - May Sarton",
        "quote_45" to "Người nông dân là một ảo thuật gia tạo ra tiền từ bùn đất. - Amit Kalantri",
        "quote_46" to "Đất là một nửa ẩn giấu của thiên nhiên. - Khuyết danh",
        "quote_47" to "Cày ruộng là nền tảng của nông nghiệp. - Khuyết danh",
        "quote_48" to "Thiên nhiên không vội vã, nhưng mọi thứ đều hoàn thành. - Lão Tử",
        "quote_49" to "Người có đất là có vàng. - Ngạn ngữ Châu Phi",
        "quote_50" to "Hãy chăm sóc đất đai và đất đai sẽ chăm sóc bạn. - Khuyết danh",
        "quote_51" to "Những người nông dân quy mô nhỏ là những anh hùng trong hệ thống thực phẩm của chúng ta. - Khuyết danh",
        "quote_52" to "Sự kiên trì là chị em song sinh của sự xuất sắc. Một cái là vấn đề chất lượng; cái kia là vấn đề thời gian. - Marabel Morgan",
        "quote_53" to "Làm việc chăm chỉ là công thức cho thành công. - Khuyết danh",
        "quote_54" to "Mồ hôi của người nông dân là mưa cho mùa màng. - Khuyết danh",
        "quote_55" to "Bạn càng làm việc chăm chỉ cho một điều gì đó, bạn sẽ càng cảm thấy tuyệt vời hơn khi đạt được nó. - Khuyết danh",
        "quote_56" to "Thành công là tổng của những nỗ lực nhỏ, được lặp đi lặp lại ngày này qua ngày khác. - Robert Collier",
        "quote_57" to "Mơ lớn, làm việc chăm chỉ, giữ tập trung. - Khuyết danh",
        "quote_58" to "Thử thách là những gì làm cho cuộc sống trở nên thú vị và vượt qua chúng là những gì làm cho cuộc sống có ý nghĩa. - Joshua J. Marine",
        "quote_59" to "Đừng chờ đợi cơ hội. Hãy tạo ra nó. - Khuyết danh",
        "quote_60" to "Bí mật của việc tiến lên phía trước là bắt đầu. - Mark Twain",
        "quote_61" to "Chất lượng không phải là một hành động, nó là một thói quen. - Aristotle",
        "quote_62" to "Tôi thấy rằng tôi càng làm việc chăm chỉ, tôi càng gặp nhiều may mắn. - Thomas Jefferson",
        "quote_63" to "Sức mạnh và sự tăng trưởng chỉ đến thông qua nỗ lực và đấu tranh liên tục. - Napoleon Hill",
        "quote_64" to "Can đảm không phải là có sức mạnh để tiếp tục; đó là tiếp tục khi bạn không còn sức mạnh. - Theodore Roosevelt",
        "quote_65" to "Con đường đến thành công luôn luôn được xây dựng. - Lily Tomlin",
        "quote_66" to "Thất bại là gia vị mang lại hương vị cho thành công. - Truman Capote",
        "quote_67" to "Đừng xấu hổ bởi những thất bại của bạn, hãy học hỏi từ chúng và bắt đầu lại. - Richard Branson",
        "quote_68" to "Những thời điểm khó khăn không tạo ra anh hùng. Chính trong những thời điểm khó khăn, 'anh hùng' bên trong chúng ta mới được bộc lộ. - Bob Riley",
        "quote_69" to "Tính cách là khả năng thực hiện một quyết tâm tốt lâu sau khi sự phấn khích của thời điểm đó đã qua đi. - Cavett Robert",
        "quote_70" to "Vụ thu hoạch của bạn sẽ đến nếu bạn không bỏ cuộc. - Khuyết danh",
        "farmer" to "Nông dân",
