        "ingredient_wheat_bran" to "Cám mì",
        "ingredient_cassava_dehydrated" to "Sắn khô",
        "ingredient_cassava_fresh" to "Sắn tươi",
        "ingredient_cassava_peels" to "Vỏ sắn",
        "ingredient_sweet_potato_fresh" to "Khoai lang tươi",
